{
	"name": "athena-code",
	"displayName": "%extension.displayName%",
	"description": "%extension.description%",
	"publisher": "Uracle",
	"version": "1.0.6",
	"icon": "assets/icons/icon.png",
	"galleryBanner": {
		"color": "#617A91",
		"theme": "dark"
	},
	"engines": {
		"vscode": "^1.84.0",
		"node": "20.19.2"
	},
	"author": {
		"name": "Athena Code"
	},
	"repository": {
		"type": "git",
		"url": "https://uracle.co.kr"
	},
	"homepage": "https://uracle.co.kr",
	"categories": [
		"AI",
		"Chat",
		"Programming Languages",
		"Education",
		"Snippets",
		"Testing"
	],
	"keywords": [
		"dev",
		"mcp",
		"openrouter",
		"coding",
		"agent",
		"autonomous",
		"chatgpt",
		"sonnet",
		"ai",
		"llama"
	],
	"activationEvents": [
		"onLanguage",
		"onStartupFinished"
	],
	"main": "./dist/extension.js",
	"contributes": {
		"viewsContainers": {
			"activitybar": [
				{
					"id": "athena-code-ActivityBar",
					"title": "%views.activitybar.title%",
					"icon": "assets/icons/icon.svg"
				}
			]
		},
		"views": {
			"athena-code-ActivityBar": [
				{
					"type": "webview",
					"id": "athena-code.SidebarProvider",
					"name": "%views.sidebar.name%"
				}
			]
		},
		"commands": [
			{
				"command": "athena-code.plusButtonClicked",
				"title": "%command.newTask.title%",
				"icon": "$(add)"
			},
			{
				"command": "athena-code.mcpButtonClicked",
				"title": "%command.mcpServers.title%",
				"icon": "$(server)"
			},
			{
				"command": "athena-code.cloudButtonClicked",
				"title": "%command.cloud.title%",
				"icon": "$(cloud)"
			},
			{
				"command": "athena-code.popoutButtonClicked",
				"title": "%command.openInEditor.title%",
				"icon": "$(link-external)"
			},
			{
				"command": "athena-code.settingsButtonClicked",
				"title": "%command.settings.title%",
				"icon": "$(settings-gear)"
			},
			{
				"command": "athena-code.openInNewTab",
				"title": "%command.openInNewTab.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.explainCode",
				"title": "%command.explainCode.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.fixCode",
				"title": "%command.fixCode.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.improveCode",
				"title": "%command.improveCode.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.addToContext",
				"title": "%command.addToContext.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.newTask",
				"title": "%command.newTask.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.terminalAddToContext",
				"title": "%command.terminal.addToContext.title%",
				"category": "Terminal"
			},
			{
				"command": "athena-code.terminalFixCommand",
				"title": "%command.terminal.fixCommand.title%",
				"category": "Terminal"
			},
			{
				"command": "athena-code.terminalExplainCommand",
				"title": "%command.terminal.explainCommand.title%",
				"category": "Terminal"
			},
			{
				"command": "athena-code.setCustomStoragePath",
				"title": "%command.setCustomStoragePath.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.importSettings",
				"title": "%command.importSettings.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.focusInput",
				"title": "%command.focusInput.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.acceptInput",
				"title": "%command.acceptInput.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.searchDocuments",
				"title": "%command.searchDocuments.title%",
				"category": "%configuration.title%",
				"icon": "$(search)"
			},
			{
				"command": "athena-code.openTask",
				"title": "%command.openTask.title%",
				"category": "%configuration.title%",
				"icon": "$(history)"
			},
			{
				"command": "athena-code.deleteTaskHistory",
				"title": "%command.deleteTaskHistory.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.visualizeGraphCodebase",
				"title": "Visualize Graph Codebase Indexing",
				"category": "%configuration.title%"
			}
		],
		"menus": {
			"editor/context": [
				{
					"submenu": "athena-code.contextMenu",
					"group": "1"
				}
			],
			"athena-code.contextMenu": [
				{
					"command": "athena-code.addToContext",
					"group": "1_actions@1"
				},
				{
					"command": "athena-code.explainCode",
					"group": "1_actions@2"
				},
				{
					"command": "athena-code.improveCode",
					"group": "1_actions@3"
				}
			],
			"terminal/context": [
				{
					"submenu": "athena-code.terminalMenu",
					"group": "2"
				}
			],
			"athena-code.terminalMenu": [
				{
					"command": "athena-code.terminalAddToContext",
					"group": "1_actions@1"
				},
				{
					"command": "athena-code.terminalFixCommand",
					"group": "1_actions@2"
				},
				{
					"command": "athena-code.terminalExplainCommand",
					"group": "1_actions@3"
				}
			],
			"view/title": [
				{
					"command": "athena-code.plusButtonClicked",
					"group": "navigation@1",
					"when": "view == athena-code.SidebarProvider"
				},
				{
					"command": "athena-code.settingsButtonClicked",
					"group": "navigation@2",
					"when": "view == athena-code.SidebarProvider"
				},
				{
					"command": "athena-code.openTask",
					"group": "navigation@3",
					"when": "view == athena-code.SidebarProvider"
				},
				{
					"command": "athena-code.cloudButtonClicked",
					"group": "navigation@4",
					"when": "view == athena-code.SidebarProvider"
				},
				{
					"command": "athena-code.mcpButtonClicked",
					"group": "navigation@5",
					"when": "view == athena-code.SidebarProvider"
				}
			],
			"editor/title": [
				{
					"command": "athena-code.plusButtonClicked",
					"group": "navigation@1",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				},
				{
					"command": "athena-code.settingsButtonClicked",
					"group": "navigation@2",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				},
				{
					"command": "athena-code.openTask",
					"group": "navigation@3",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				},
				{
					"command": "athena-code.cloudButtonClicked",
					"group": "navigation@4",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				},
				{
					"command": "athena-code.mcpButtonClicked",
					"group": "navigation@5",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				}
			]
		},
		"submenus": [
			{
				"id": "athena-code.contextMenu",
				"label": "%views.contextMenu.label%"
			},
			{
				"id": "athena-code.terminalMenu",
				"label": "%views.terminalMenu.label%"
			}
		],
