{
	"name": "athena-code",
	"displayName": "%extension.displayName%",
	"description": "%extension.description%",
	"publisher": "Uracle",
	"version": "1.0.6",
	"icon": "assets/icons/icon.png",
	"galleryBanner": {
		"color": "#617A91",
		"theme": "dark"
	},
	"engines": {
		"vscode": "^1.84.0",
		"node": "20.19.2"
	},
	"author": {
		"name": "Athena Code"
	},
	"repository": {
		"type": "git",
		"url": "https://uracle.co.kr"
	},
	"homepage": "https://uracle.co.kr",
	"categories": [
		"AI",
		"Chat",
		"Programming Languages",
		"Education",
		"Snippets",
		"Testing"
	],
	"keywords": [
		"dev",
		"mcp",
		"openrouter",
		"coding",
		"agent",
		"autonomous",
		"chatgpt",
		"sonnet",
		"ai",
		"llama"
	],
	"activationEvents": [
		"onLanguage",
		"onStartupFinished"
	],
	"main": "./dist/extension.js",
	"contributes": {
		"viewsContainers": {
			"activitybar": [
				{
					"id": "athena-code-ActivityBar",
					"title": "%views.activitybar.title%",
					"icon": "assets/icons/icon.svg"
				}
			]
		},
		"views": {
			"athena-code-ActivityBar": [
				{
					"type": "webview",
					"id": "athena-code.SidebarProvider",
					"name": "%views.sidebar.name%"
				}
			]
		},
		"commands": [
			{
				"command": "athena-code.plusButtonClicked",
				"title": "%command.newTask.title%",
				"icon": "$(add)"
			},
			{
				"command": "athena-code.mcpButtonClicked",
				"title": "%command.mcpServers.title%",
				"icon": "$(server)"
			},
			{
				"command": "athena-code.cloudButtonClicked",
				"title": "%command.cloud.title%",
				"icon": "$(cloud)"
			},
			{
				"command": "athena-code.popoutButtonClicked",
				"title": "%command.openInEditor.title%",
				"icon": "$(link-external)"
			},
			{
				"command": "athena-code.settingsButtonClicked",
				"title": "%command.settings.title%",
				"icon": "$(settings-gear)"
			},
			{
				"command": "athena-code.openInNewTab",
				"title": "%command.openInNewTab.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.explainCode",
				"title": "%command.explainCode.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.fixCode",
				"title": "%command.fixCode.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.improveCode",
				"title": "%command.improveCode.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.addToContext",
				"title": "%command.addToContext.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.newTask",
				"title": "%command.newTask.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.terminalAddToContext",
				"title": "%command.terminal.addToContext.title%",
				"category": "Terminal"
			},
			{
				"command": "athena-code.terminalFixCommand",
				"title": "%command.terminal.fixCommand.title%",
				"category": "Terminal"
			},
			{
				"command": "athena-code.terminalExplainCommand",
				"title": "%command.terminal.explainCommand.title%",
				"category": "Terminal"
			},
			{
				"command": "athena-code.setCustomStoragePath",
				"title": "%command.setCustomStoragePath.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.importSettings",
				"title": "%command.importSettings.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.focusInput",
				"title": "%command.focusInput.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.acceptInput",
				"title": "%command.acceptInput.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.searchDocuments",
				"title": "%command.searchDocuments.title%",
				"category": "%configuration.title%",
				"icon": "$(search)"
			},
			{
				"command": "athena-code.openTask",
				"title": "%command.openTask.title%",
				"category": "%configuration.title%",
				"icon": "$(history)"
			},
			{
				"command": "athena-code.deleteTaskHistory",
				"title": "%command.deleteTaskHistory.title%",
				"category": "%configuration.title%"
			},
			{
				"command": "athena-code.visualizeGraphCodebase",
				"title": "Visualize Graph Codebase Indexing",
				"category": "%configuration.title%"
			}
		],
		"menus": {
			"editor/context": [
				{
					"submenu": "athena-code.contextMenu",
					"group": "1"
				}
			],
			"athena-code.contextMenu": [
				{
					"command": "athena-code.addToContext",
					"group": "1_actions@1"
				},
				{
					"command": "athena-code.explainCode",
					"group": "1_actions@2"
				},
				{
					"command": "athena-code.improveCode",
					"group": "1_actions@3"
				}
			],
			"terminal/context": [
				{
					"submenu": "athena-code.terminalMenu",
					"group": "2"
				}
			],
			"athena-code.terminalMenu": [
				{
					"command": "athena-code.terminalAddToContext",
					"group": "1_actions@1"
				},
				{
					"command": "athena-code.terminalFixCommand",
					"group": "1_actions@2"
				},
				{
					"command": "athena-code.terminalExplainCommand",
					"group": "1_actions@3"
				}
			],
			"view/title": [
				{
					"command": "athena-code.plusButtonClicked",
					"group": "navigation@1",
					"when": "view == athena-code.SidebarProvider"
				},
				{
					"command": "athena-code.settingsButtonClicked",
					"group": "navigation@2",
					"when": "view == athena-code.SidebarProvider"
				},
				{
					"command": "athena-code.openTask",
					"group": "navigation@3",
					"when": "view == athena-code.SidebarProvider"
				},
				{
					"command": "athena-code.cloudButtonClicked",
					"group": "navigation@4",
					"when": "view == athena-code.SidebarProvider"
				},
				{
					"command": "athena-code.mcpButtonClicked",
					"group": "navigation@5",
					"when": "view == athena-code.SidebarProvider"
				}
			],
			"editor/title": [
				{
					"command": "athena-code.plusButtonClicked",
					"group": "navigation@1",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				},
				{
					"command": "athena-code.settingsButtonClicked",
					"group": "navigation@2",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				},
				{
					"command": "athena-code.openTask",
					"group": "navigation@3",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				},
				{
					"command": "athena-code.cloudButtonClicked",
					"group": "navigation@4",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				},
				{
					"command": "athena-code.mcpButtonClicked",
					"group": "navigation@5",
					"when": "activeWebviewPanelId == athena-code.TabPanelProvider"
				}
			]
		},
		"submenus": [
			{
				"id": "athena-code.contextMenu",
				"label": "%views.contextMenu.label%"
			},
			{
				"id": "athena-code.terminalMenu",
				"label": "%views.terminalMenu.label%"
			}
		],
		"configuration": {
			"title": "%configuration.title%",
			"properties": {
				"athena-code.allowedCommands": {
					"type": "array",
					"items": {
						"type": "string"
					},
					"default": [
						"npm test",
						"npm install",
						"tsc",
						"git log",
						"git diff",
						"git show"
					],
					"description": "%commands.allowedCommands.description%"
				},
				"athena-code.deniedCommands": {
					"type": "array",
					"items": {
						"type": "string"
					},
					"default": [],
					"description": "%commands.deniedCommands.description%"
				},
				"athena-code.commandExecutionTimeout": {
					"type": "number",
					"default": 0,
					"minimum": 0,
					"maximum": 600,
					"description": "%commands.commandExecutionTimeout.description%"
				},
				"athena-code.vsCodeLmModelSelector": {
					"type": "object",
					"properties": {
						"vendor": {
							"type": "string",
							"description": "%settings.vsCodeLmModelSelector.vendor.description%"
						},
						"family": {
							"type": "string",
							"description": "%settings.vsCodeLmModelSelector.family.description%"
						}
					},
					"description": "%settings.vsCodeLmModelSelector.description%"
				},
				"athena-code.customStoragePath": {
					"type": "string",
					"default": "",
					"description": "%settings.customStoragePath.description%"
				},
				"athena-code.enableCodeActions": {
					"type": "boolean",
					"default": true,
					"description": "%settings.enableCodeActions.description%"
				},
				"athena-code.autoImportSettingsPath": {
					"type": "string",
					"default": "",
					"description": "%settings.autoImportSettingsPath.description%"
				}
			}
		}
	},
	"scripts": {
		"lint": "eslint . --ext=ts --max-warnings=0",
		"check-types": "tsc --noEmit",
		"pretest": "turbo run bundle --cwd ..",
		"test": "vitest run",
		"format": "prettier --write .",
		"bundle": "node esbuild.mjs",
		"vsix": "mkdirp ../bin && pnpm bundle --production && vsce package --no-dependencies --out ../bin",
		"publish:marketplace": "vsce publish --no-dependencies && ovsx publish --no-dependencies",
		"watch:bundle": "pnpm bundle --watch",
		"watch:tsc": "cd .. && tsc --noEmit --watch --project src/tsconfig.json",
		"clean": "rimraf README.md CHANGELOG.md LICENSE dist mock .turbo"
	},
